data class ApiResponse<T>(
    val success: Boolean,
    val data: T? = null,
    val error: ErrorDetail? = null
) {
    data class ErrorDetail(
        val code: String,
        val message: String
    )
}

data class ApiResponse<T>(
    val success: Boolean,
    val data: T? = null,
    val error: ErrorDetail? = null
) {
    companion object {
        fun <T> success(data: T): ApiResponse<T> = ...
        fun <T> error(errorCode: ErrorCode): ApiResponse<T> = ...
    }
}

@RestControllerAdvice
class GlobalExceptionHandler {

    @ExceptionHandler(BusinessException::class)
    fun handleBusinessException(e: BusinessException): ResponseEntity<ApiResponse<Nothing>> {
        val status = when (e.errorCode) {
            ErrorCode.NOT_FOUND -> HttpStatus.NOT_FOUND
            ErrorCode.UNAUTHORIZED -> HttpStatus.UNAUTHORIZED
            ErrorCode.CIRCUIT_BREAKER_OPEN, ErrorCode.EXTERNAL_API_ERROR -> HttpStatus.SERVICE_UNAVAILABLE
            else -> HttpStatus.INTERNAL_SERVER_ERROR
        }
        return ResponseEntity.status(status).body(ApiResponse.error(e.errorCode))
    }

enum class ErrorCode(val message: String) {
    INVALID_INPUT("입력값이 올바르지 않습니다"),
    NOT_FOUND("리소스를 찾을 수 없습니다"),
    UNAUTHORIZED("인증이 필요합니다"),
    CIRCUIT_BREAKER_OPEN("서비스가 일시적으로 사용 불가능합니다"),
    EXTERNAL_API_ERROR("외부 API 호출에 실패했습니다"),
    INSUFFICIENT_STOCK("재고가 부족합니다"),
    INVALID_ORDER_STATUS("유효하지 않은 주문 상태입니다")
    // ...
}

open class BusinessException(
    val errorCode: ErrorCode,
    message: String = errorCode.message,
    cause: Throwable? = null
) : RuntimeException(message, cause)

class NotFoundException(resource: String, id: Any? = null) : BusinessException(...)
class UnauthorizedException(...) : BusinessException(...)
class ForbiddenException(...) : BusinessException(...)

