fun publish(event: AnalyticsEvent) {
    kafkaTemplate.send(TOPIC, event.visitorId, event)
        .whenComplete { _, ex ->
            if (ex != null) {
                log.warn("Analytics event publish failed: {}", event.eventId, ex)
            }
        }
}

